import{_ as a,o as t,c as r,ai as o}from"./chunks/framework.CCqJdmEn.js";const f=JSON.parse('{"title":"Software","description":"","frontmatter":{},"headers":[],"relativePath":"software/index.md","filePath":"software/index.md"}'),i={name:"software/index.md"};function n(s,e,h,l,p,d){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="software" tabindex="-1">Software <a class="header-anchor" href="#software" aria-label="Permalink to &quot;Software&quot;">​</a></h1><p>Numerous software packages and tools have been developed in the context of different projects of the Kohlbacher Lab.</p><h2 id="openms" tabindex="-1">OpenMS <a class="header-anchor" href="#openms" aria-label="Permalink to &quot;OpenMS&quot;">​</a></h2><p><a href="./open-ms.html">OpenMS</a> is an open-source software for mass spectrometry analysis.<br> Project Website: <a href="https://www.openms.de" target="_blank" rel="noreferrer">https://www.openms.de</a><br> Repository: <a href="https://github.com/OpenMS/OpenMS" target="_blank" rel="noreferrer">https://github.com/OpenMS/OpenMS</a></p><h2 id="fred2" tabindex="-1">Fred2 <a class="header-anchor" href="#fred2" aria-label="Permalink to &quot;Fred2&quot;">​</a></h2><p><a href="./fred-2.html">Fred2</a> is a python-based framework for computational immunomics.<br> Project Website: <a href="https://fred-2.github.io" target="_blank" rel="noreferrer">https://fred-2.github.io</a><br> Repository: <a href="https://github.com/FRED-2/Fred2" target="_blank" rel="noreferrer">https://github.com/FRED-2/Fred2</a></p><h2 id="claudio" tabindex="-1">Claudio <a class="header-anchor" href="#claudio" aria-label="Permalink to &quot;Claudio&quot;">​</a></h2><p><a href="./claudio.html">CLAUDIO</a> is a tool for structural analysis, mapping, validation, visualization, and modeling of protein cross-links on protein and protein-protein interaction.<br> Repository: <a href="https://github.com/KohlbacherLab/CLAUDIO" target="_blank" rel="noreferrer">https://github.com/KohlbacherLab/CLAUDIO</a></p><h2 id="dnpm-dip" tabindex="-1">DNPM:DIP <a class="header-anchor" href="#dnpm-dip" aria-label="Permalink to &quot;DNPM:DIP&quot;">​</a></h2><p>The <a href="./dnpm-dip.html">Data Integration Platform</a> (DIP) for the German Network of Personalized Medicine (DNPM).<br> Project Website: <a href="https://docs.dnpm-dip.net/%5C" target="_blank" rel="noreferrer">https://docs.dnpm-dip.net/\\</a> Repository: <a href="https://github.com/dnpm-dip" target="_blank" rel="noreferrer">https://github.com/dnpm-dip</a></p><h2 id="flame" tabindex="-1">FLAME <a class="header-anchor" href="#flame" aria-label="Permalink to &quot;FLAME&quot;">​</a></h2><p><a href="./flame.html">FLAME</a> (Federated Learning and Analyses in Medicine) is the open-source core of the <a href="./../projects/privateaim.html">PrivateAIM</a> initiative, enabling secure, decentralized data analysis across institutions without sharing patient data.<br> Code: <a href="https://github.com/PrivateAim" target="_blank" rel="noreferrer">https://github.com/PrivateAim</a> <br> Documentation: <a href="https://docs.privateaim.net/" target="_blank" rel="noreferrer">https://docs.privateaim.net/</a></p><h2 id="xlec" tabindex="-1">XLEC <a class="header-anchor" href="#xlec" aria-label="Permalink to &quot;XLEC&quot;">​</a></h2><p><a href="./xlec.html">XLEC</a> is an integrative approach combining cross-linking data and evolutionary couplings for large-scale prediction and modeling of protein-protein interactions. Repository: <a href="https://github.com/KohlbacherLab/XLEC" target="_blank" rel="noreferrer">https://github.com/KohlbacherLab/XLEC</a></p>',14)])])}const m=a(i,[["render",n]]);export{f as __pageData,m as default};
